import { workflow, node, trigger, newCredential, expr } from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const approvalTest = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'approval test',
    parameters: {
      assignments: {
        assignments: [
          { id: '1', name: 'status', value: 'approved', type: 'string' }
        ]
      },
      options: {}
    }
  }
});

export default workflow('approval-test', 'Approval Test')
  .add(manualTrigger)
  .to(approvalTest);
